import redis
import json
from functools import wraps
import hashlib

redis_client = redis.Redis(host='localhost', port=6379, decode_responses=True)

def cache_aside(key_prefix: str, ttl: int = 3600, key_builder=None):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if key_builder:
                cache_key = f"{key_prefix}:{key_builder(*args, **kwargs)}"
            else:
                key_data = f"{args}:{sorted(kwargs.items())}"
                key_hash = hashlib.md5(key_data.encode()).hexdigest()[:12]
                cache_key = f"{key_prefix}:{key_hash}"

            # Try cache first
            cached = redis_client.get(cache_key)
            if cached:
                return json.loads(cached)

            # Cache miss - call function
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, ttl, json.dumps(result))
            return result

        wrapper.invalidate = lambda *args, **kwargs: redis_client.delete(
            f"{key_prefix}:{key_builder(*args, **kwargs)}" if key_builder else f"{key_prefix}:*"
        )
        return wrapper
    return decorator

# Usage — always supply key_builder for deterministic keys
@cache_aside("user", ttl=1800, key_builder=lambda user_id: user_id)
def get_user(user_id: str):
    return db.users.find_one({"_id": user_id})

def update_user(user_id: str, data: dict):
    db.users.update_one({"_id": user_id}, {"$set": data})
    get_user.invalidate(user_id)

package cache

import (
    "context"
    "encoding/json"
    "time"
    "github.com/go-redis/redis/v8"
)

type CacheManager struct {
    client *redis.Client
}

func NewCacheManager(addr string) *CacheManager {
    return &CacheManager{
        client: redis.NewClient(&redis.Options{Addr: addr}),
    }
}

func (c *CacheManager) CacheAside(
    ctx context.Context,
    key string,
    ttl time.Duration,
    loader func() (interface{}, error),
) (interface{}, error) {
    cached, err := c.client.Get(ctx, key).Result()
    if err == nil {
        var result interface{}
        json.Unmarshal([]byte(cached), &result)
        return result, nil
    }

    data, err := loader()
    if err != nil {
        return nil, err
    }

    encoded, _ := json.Marshal(data)
    c.client.Set(ctx, key, encoded, ttl)
    return data, nil
}

import { createClient, RedisClientType } from 'redis';

interface CacheOptions {
  ttl?: number;
  prefix?: string;
}

class CacheManager {
  private client: RedisClientType;

  constructor(redisUrl: string = 'redis://localhost:6379') {
    this.client = createClient({ url: redisUrl });
    this.client.connect();
  }

  async cacheAside<T>(
    key: string,
    loader: () => Promise<T>,
    options: CacheOptions = {}
  ): Promise<T> {
    const { ttl = 3600, prefix = 'cache' } = options;
    const fullKey = `${prefix}:${key}`;

    const cached = await this.client.get(fullKey);
    if (cached) {
      return JSON.parse(cached) as T;
    }

    const data = await loader();
    await this.client.setEx(fullKey, ttl, JSON.stringify(data));
    return data;
  }

  async invalidate(pattern: string, prefix: string = 'cache'): Promise<void> {
    const fullPattern = `${prefix}:${pattern}`;
    const keys = [];
    for await (const key of this.client.scanIterator({ MATCH: fullPattern, COUNT: 100 })) {
      keys.push(key);
    }
    if (keys.length > 0) {
      await this.client.del(keys);
    }
  }
}

import json
import redis

class WriteThroughCache:
    def __init__(self, redis_client, db, collection_name: str, ttl: int = 3600):
        self.redis = redis_client
        self.collection = db[collection_name]
        self.ttl = ttl
        self.key_prefix = collection_name

    def _cache_key(self, doc_id: str) -> str:
        return f"{self.key_prefix}:{doc_id}"

    def get(self, doc_id: str):
        cached = self.redis.get(self._cache_key(doc_id))
        if cached:
            return json.loads(cached)

        doc = self.collection.find_one({"_id": doc_id})
        if doc:
            self.redis.setex(self._cache_key(doc_id), self.ttl, json.dumps(doc))
        return doc

    def set(self, doc_id: str, data: dict):
        # Write to DB first
        self.collection.update_one({"_id": doc_id}, {"$set": data}, upsert=True)

        # Then update cache with the freshly persisted document
        doc = self.collection.find_one({"_id": doc_id})
        self.redis.setex(self._cache_key(doc_id), self.ttl, json.dumps(doc))
        return doc

    def delete(self, doc_id: str):
        self.collection.delete_one({"_id": doc_id})
        self.redis.delete(self._cache_key(doc_id))

import asyncio import json from collections import defaultdict from datetime import datetime from pymongo import UpdateOne
class WriteBehindCache: def __init__(self, redis_client, db, flush_interval: int = 5): self.redis = redis_client self.db = db self.flush_interval = flush_interval self.pending_writes = defaultdict(dict)
async def set(self, collection: str, doc_id: str, data: dict): # Write to cache immediately cache_key = f"{collection}:{doc_id}" self.redis.setex(cache_key, 3600, json.dumps(data))
# Queue for async DB write self.pending_writes[collection][doc_id] = { "data": data, "timestamp": datetime.utcnow() }
async def _flush_loop(self): while True: await asyncio.sleep(self.flush_interval) await self._flush_all()
async def _flush_all(self): for collection, docs in list(self.pending_writes.items()): if not docs: continue
operations = [ UpdateOne({"_id": doc_id}, {"$set": doc_info["data"]}, upsert=True) for doc_id, doc_info in docs.items() ]
if operations: self.db[collection].bulk_write(operations) self.pending_writes[collection].clear()
